export default {
  title: 'Shared Components/Popper',
  component: Popper,
} satisfies Meta;

const buttonWidth = 80;
const spaceSize = 24;

const Button = React.memo(_Button);
// const Button = _Button;

const RecursizePopover = ({ prefix = '' }: { prefix?: string }) => (
  <Space direction="vertical">
    {!prefix.match('r-r-r')
      ? [0, 1, 2].map(o => {
          const trigger = o === 0 ? 'click' : o === 1 ? 'hover' : 'contextMenu';
          return (
            <Popper
              key={o}
              offset={10}
              popup={
                <div className={popoverCss}>
                  <RecursizePopover prefix={`r-${prefix}=${o}`} />
                </div>
              }
              trigger={trigger}
              enableMaxHeight
            >
              <Button id={`${prefix}-${trigger}-${o}`}>{`${prefix}-${trigger}-${o}`}</Button>
            </Popper>
          );
        })
      : null}
  </Space>
);

const Log = ({ name }: { name: string }) => {
  useLogger(name);
  return null;
};

const Tooltip = ({ placement }: { placement: Placement }) => {
  const [vis, setVis] = React.useState(false);
  React.useLayoutEffect(() => {
    console.log('Tooltip.useLayoutEffect', document.getElementById('gux-click-0'));
    Promise.resolve().then(() => {
      console.log('Promise Tooltip.useLayoutEffect', document.getElementById('gux-click-0'));
    });
  });
  return (
    <Popper
      // visible={placement === 'bottomLeft' || placement === 'bottomRight'}
      visible={vis}
      onVisibleChange={setVis}
      arrow={<PopperArrow hasStroke />}
      arrowPadding={8 + 8}
      offset={4 + 6}
      placement={placement}
      popup={
        <div className={popoverCss}>
          <div style={{ overflowWrap: 'anywhere' }}>
            <Log name={`${placement} tooltip child`} />
            <RecursizePopover prefix="gux" />
            <PerformanceContent
              componentName={`Popup ${placement}`}
              count={1000}
              itemRenderer={i =>
                placement === 'bottom-start' ? (
                  <Popper arrow={<PopperArrow />} popup={placement.repeat(1000)} enableMaxHeight>
                    <div>{placement}</div>
                  </Popper>
                ) : (
                  <OldPopper
                    // showAction={['click', 'contextMenu', 'mouseEnter']}
                    // hideAction={['click', 'mouseLeave']}
                    content={placement.repeat(1000)}
                  >
                    <div>{placement}</div>
                  </OldPopper>
                )
              }
            />
          </div>
        </div>
      }
      trigger={['click']}
      // enableMaxHeight
      // matchReferenceWidth
      Transition={SlideUpDownTransition}
    >
      <Button style={{ width: buttonWidth }}>{placement}</Button>
    </Popper>
  );
};

