const ActionTestRecursizePopover = ({
  prefix = 'root',
  size = 2,
  ...restProps
}: {
  prefix?: string;
  size?: number;
} & Pick<PopperProps, 'trigger' | 'showAction' | 'hideAction' | 'disabled'>) => (
  <>
    {Array(size)
      .fill(0)
      .map((_, i) => (
        <Popper
          arrow={<PopperArrow />}
          offset={10}
          popupClassName={`${prefix}-${i}-popup`}
          key={i}
          popup={
            <div
              id={`${prefix}-${i}-popup`}
              style={{
                border: '1px solid var(--line-border-component)',
                background: 'white',
                padding: 16,
              }}
            >
              <ActionTestRecursizePopover prefix={`${prefix}-${i}`} {...restProps} />
            </div>
          }
          {...restProps}
        >
          <button
            id={`${prefix}-${i}-button`}
            type="button"
            style={{
              margin: 16,
            }}
          >
            {`${prefix}-${i}`}
          </button>
        </Popper>
      ))}
  </>
);

export const ActionTest = () => {
  const props: React.ComponentProps<typeof ActionTestRecursizePopover>[] = [
    {
      trigger: 'hover',
    },
    {
      trigger: 'click',
    },
    {
      trigger: 'contextMenu',
    },
    {
      trigger: 'hover',
      hideAction: ['click'],
    },
    {
      trigger: 'click',
      hideAction: ['mouseLeave'],
    },
    {
      trigger: 'hover',
      showAction: ['click'],
    },
    {
      trigger: 'click',
      showAction: ['mouseEnter'],
    },
    {
      showAction: ['click'],
      hideAction: ['mouseLeave'],
    },
    {
      showAction: ['contextMenu'],
      hideAction: ['mouseLeave'],
    },
    {
      showAction: ['mouseEnter'],
      hideAction: ['click'],
    },
  ];
  return (
    <>
      {props.map(o => (
        <div key={JSON.stringify(o)}>
          <h6>{JSON.stringify(o)}</h6>
          <ActionTestRecursizePopover {...o} />
        </div>
      ))}
    </>
  );
};

interface FormValues {
  adjustY: boolean;
  adjustX: boolean;
  open: boolean;
  placement: PositionType;
  offset: { x: number; y: number };
}

export const ComparePopupAlign = () => (
  <div>
    <div style={{ height: 800 }} />
    <Form<FormValues>
      layout="inline"
      initialValues={{
        adjustY: false,
        adjustX: false,
        open: true,
        placement: 'top',
        offset: {
          x: 8,
          y: -4,
        },
      }}
    >
      <Form.Item label="Open" name="open" valuePropName="checked">
        <Switch />
      </Form.Item>
      <Form.Item label="AdjustX" name="adjustX" valuePropName="checked">
        <Checkbox />
      </Form.Item>
      <Form.Item label="AdjustY" name="adjustY" valuePropName="checked">
        <Checkbox />
      </Form.Item>
      <Form.Item label="Placement" name="placement">
        <Select
          style={{ width: 200 }}
          options={PositionEnum.map(o => ({ value: o }))}
          allowClear={false}
          dropdownMatchSelectWidth={false}
        />
      </Form.Item>
      <Form.Item label="Offset.x" name={['offset', 'x']}>
        <InputNumber />
      </Form.Item>
      <Form.Item label="Offset.y" name={['offset', 'y']}>
        <InputNumber />
      </Form.Item>
      <FormSelector selector={(o: FormContextType<FormValues>) => o.values}>
        {({ adjustX, adjustY, open, placement, offset }) => {
          const align = {
            points: getPlacements({
              offset: 0,
              defaultOffset: 0,
            })[placement].points,
            offset: [offset.x, offset.y],
            overflow: {
              adjustX,
              adjustY,
            },
          };
          const content = Array(100)
            .fill(0)
            .map((_, i) => i)
            .join(', ');
          return (
            <Space direction="vertical" inline={false} align="center">
              <Space
                style={{
                  width: '100%',
                  justifyContent: 'center',
                  marginTop: 200,
                }}
                size={400}
              >
                <ConfigProvider>
                  <OldPopper visible={open} trigger="click" content={content} popupAlign={align} placement="bottomLeft">
                    <Button>Popover</Button>
                  </OldPopper>
                </ConfigProvider>
                <ConfigProvider PopperSidecar={FloatingUIPopperSidecar}>
                  <OldPopper visible={open} trigger="click" content={content} popupAlign={align} placement="bottomLeft">
                    <Button>Popover, FloatingUIPopperSidecar</Button>
                  </OldPopper>
                </ConfigProvider>
              </Space>
              <Space
                style={{
                  width: '100%',
                  justifyContent: 'center',
                  marginTop: 200,
                }}
                size={400}
              >
                <ConfigProvider>
                  <Dropdown
                    visible={open}
                    trigger="click"
                    overlay={<div className={popoverCss}>{content}</div>}
                    align={align}
                    placement="bottomLeft"
                  >
                    <Button>Dropdown</Button>
                  </Dropdown>
                </ConfigProvider>
                <ConfigProvider PopperSidecar={FloatingUIPopperSidecar}>
                  <Dropdown
                    visible={open}
                    trigger="click"
                    overlay={<div className={popoverCss}>{content}</div>}
                    align={align}
                    placement="bottomLeft"
                  >
                    <Button>Dropdown, FloatingUIPopperSidecar</Button>
                  </Dropdown>
                </ConfigProvider>
              </Space>
            </Space>
          );
        }}
      </FormSelector>
    </Form>
    <div style={{ height: 800 }} />
  </div>
);
